import React, { useState, useEffect, useCallback, useRef } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { CheckCircle, Loader2, Bike, Store, XCircle } from 'lucide-react';

const MisPedidosCliente = () => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [progresoEnvio, setProgresoEnvio] = useState({}); 
  const { user } = useAuth();
  
  // Usamos un Ref para evitar bucles infinitos en el guardado automático
  const guardadosRef = useRef(new Set());

  const fetchPedidos = useCallback(async () => {
    try {
      const clienteId = user?.id || user?._id;
      if (!clienteId) return;
      const data = await api.getPedidosCliente(clienteId);
      setPedidos(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error al obtener pedidos:", error);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) fetchPedidos();
  }, [user, fetchPedidos]);

  // LÓGICA DE MOVIMIENTO Y ACTUALIZACIÓN AUTOMÁTICA
  useEffect(() => {
    const intervals = [];
    
    pedidos.forEach(pedido => {
      const estado = pedido.estado?.toLowerCase();
      
      // Si el pedido está en 'camino', iniciamos la simulación
      if (estado === 'camino') {
        const interval = setInterval(async () => {
          setProgresoEnvio(prev => {
            const actual = prev[pedido._id] || 0;
            
            if (actual >= 100) {
              clearInterval(interval);
              
              // Solo disparamos la actualización a la DB una vez por pedido
              if (!guardadosRef.current.has(pedido._id)) {
                guardadosRef.current.add(pedido._id);
                actualizarEstadoEntregado(pedido._id);
              }
              return prev;
            }
            return { ...prev, [pedido._id]: actual + 1 };
          });
        }, 300); // 300ms * 100 pasos = 30 segundos de viaje
        intervals.push(interval);
      }
    });

    return () => intervals.forEach(id => clearInterval(id));
  }, [pedidos]);

  const actualizarEstadoEntregado = async (pedidoId) => {
    try {
      // Llamada al backend para cambiar estado de 'camino' a 'completado'
      await api.patch(`/api/pedidos/${pedidoId}/estado`, { estado: 'completado' });
      console.log(`Pedido ${pedidoId} marcado como entregado en Atlas`);
    } catch (err) {
      console.error("Error al auto-finalizar pedido:", err);
    }
  };

  const handleCancelar = async (pedidoId) => {
    if (!window.confirm("¿Deseas cancelar este pedido?")) return;
    try {
      await api.cancelarPedido(pedidoId);
      fetchPedidos(); 
    } catch (err) {
      alert("Error: " + err.message);
    }
  };

  if (loading) return <div style={msgContainer}><Loader2 className="animate-spin" color="#3182ce" /></div>;

  return (
    <div style={container}>
      <header style={headerStyle}>
        <h2 style={title}>Mis Pedidos</h2>
        <span style={badgeCount}>{pedidos.length} activos</span>
      </header>

      <div style={listContainer}>
        {pedidos.length === 0 ? (
          <div style={emptyState}>Aún no has realizado pedidos.</div>
        ) : (
          pedidos.map((pedido) => {
            const estado = pedido.estado?.toLowerCase();
            const p = estado === 'completado' ? 100 : (progresoEnvio[pedido._id] || 0);
            const entregado = p >= 100 || estado === 'completado';

            return (
              <div key={pedido._id} style={orderCard}>
                <div style={orderHeader}>
                  <span style={dateText}>PEDIDO #{pedido._id?.slice(-6).toUpperCase()}</span>
                  <span style={{...statusText, color: entregado ? '#059669' : '#3182ce'}}>
                    {entregado ? '¡ENTREGADO!' : 'EN CAMINO...'}
                  </span>
                </div>

                <div style={stepperWrapper}>
                  {/* Barra de progreso */}
                  <div style={stepperBackground}>
                    <div style={{ ...stepperFill, width: `${p}%`, backgroundColor: entregado ? '#059669' : '#3182ce' }} />
                  </div>
                  
                  {/* Iconos de las etapas */}
                  <div style={nodesContainer}>
                    <div style={nodeGroup}>
                        <div style={{...iconCircle, backgroundColor: p >= 0 ? '#3182ce' : '#e2e8f0'}}><Store size={14} color="white"/></div>
                        <span style={nodeLabel}>Local</span>
                    </div>
                    <div style={nodeGroup}>
                        <div style={{...iconCircle, backgroundColor: p >= 50 ? '#3182ce' : '#e2e8f0', transform: `translateX(${p < 100 ? (p/2) : 0}px)`}}>
                            <Bike size={14} color="white"/>
                        </div>
                        <span style={nodeLabel}>Reparto</span>
                    </div>
                    <div style={nodeGroup}>
                        <div style={{...iconCircle, backgroundColor: p >= 100 ? '#059669' : '#e2e8f0'}}><CheckCircle size={14} color="white"/></div>
                        <span style={nodeLabel}>Llegó</span>
                    </div>
                  </div>
                </div>

                <div style={bodyCard}>
                  <div style={infoRow}>
                    <h4 style={localName}>{pedido.local?.nombre || 'Cargando local...'}</h4>
                    <span style={totalPrice}>${pedido.total?.toLocaleString()}</span>
                  </div>

                  {estado === 'camino' && p < 20 && (
                    <button onClick={() => handleCancelar(pedido._id)} style={cancelButton}>
                      <XCircle size={14} /> Cancelar Pedido
                    </button>
                  )}
                  
                  {entregado && (
                    <div style={successMsg}>Gracias por comprar en {pedido.local?.nombre}</div>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const container = { padding: '20px', maxWidth: '500px', margin: '0 auto', backgroundColor: '#f8fafc', minHeight: '100vh' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' };
const title = { fontWeight: '900', fontSize: '1.5rem', color: '#1e293b', margin: 0 };
const badgeCount = { background: '#e2e8f0', padding: '4px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 'bold' };
const listContainer = { display: 'flex', flexDirection: 'column', gap: '20px' };
const orderCard = { background: '#fff', borderRadius: '24px', border: '1px solid #e2e8f0', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const orderHeader = { padding: '15px 20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc', borderBottom: '1px solid #f1f5f9' };
const dateText = { fontSize: '0.75rem', fontWeight: 'bold', color: '#94a3b8', letterSpacing: '0.5px' };
const statusText = { fontSize: '0.75rem', fontWeight: '900' };

const stepperWrapper = { padding: '40px 40px 30px 40px', position: 'relative' };
const stepperBackground = { height: '6px', background: '#f1f5f9', borderRadius: '10px' };
const stepperFill = { height: '100%', borderRadius: '10px', transition: 'width 0.3s ease, background-color 0.5s' };
